INSERT INTO pages (title, slug, content, page_type, seo_title, seo_description, focus_keyword, related_categories, status) VALUES ('Roofing Contractor Marketing', 'roofing-contractor-marketing', '# Roofing Contractor Marketing That Gets You Leads

 
