INSERT INTO posts (title, slug, content, excerpt, featured_image, seo_title, seo_description, focus_keyword, published_at, status) VALUES ('The Importance of ADA Compliance for Your Website', 'the-importance-of-ada-compliance-for-your-website', '## Table of Contents

 - 

 [Introduction](#introduction-MCbrOYqFTz)
 - [How to Ensure Your Website is ADA Compliant and What to Do if It Isn’t](#how-to-ensure-your-website-is-ada-compliant-and-what-to-do-if-it-isnt-MCbrOYqFTz)
